+                 "{%4, %5};\n"
+                 : "=r"(d0), "=r"(d1)
+                 : "r"(a0), "r"(b0), "r"(c0), "r"(c1));
+#else
+    CUTE_INVALID_CONTROL_PATH(
+        "Attempting to use SM75_8x8x32_S32U4U4S32_TN without "
+        "CUTE_ARCH_MMA_SM75_ENABLED");
+#endif
+  }
+};
